// InmoLawyer - Extractor v5.1 - Con preservación de binario
const inputItem = $input.first();
const inputData = inputItem.json;
const textoContrato = inputData.texto || inputData.body?.texto || inputData.text || inputData.data || '';
const archivoNombre = inputData.archivoNombre || inputData.body?.archivoNombre || inputData.fileName || 'contrato.pdf';

const limpiarTexto = (str) => str ? str.trim().replace(/\s+/g, ' ') : null;
const extraerNumero = (str) => str ? str.replace(/[^0-9]/g, '') : null;
const parsearMoneda = (str) => { 
  if (!str) return null; 
  const limpio = str.replace(/[$\s]/g, '').replace(/\./g, '').replace(',', '.');
  const num = parseFloat(limpio);
  return (num > 10000 && num < 100000000) ? num : null;
};

function extraerDatosContrato(texto) {
  const data = { 
    arrendador_nombre: null, arrendador_doc: null, 
    arrendatario_nombre: null, arrendatario_doc: null, 
    canon: null, fecha_inicio: null, duracion_meses: null, 
    direccion: null, ciudad: null 
  };

  // ========== ARRENDADOR ==========
  let matchArr = texto.match(/Parte\s+Arrendadora\s+([A-ZÁÉÍÓÚÑ][A-Za-záéíóúñÁÉÍÓÚÑ\s]+?)(?:\n|CC|C\.C\.|$)/i);
  if (matchArr && matchArr[1]) {
    data.arrendador_nombre = limpiarTexto(matchArr[1]);
  }

  if (!data.arrendador_nombre) {
    matchArr = texto.match(/(?:EL\s+)?ARRENDADOR[,:;\s]+([A-ZÁÉÍÓÚÑ][A-Za-záéíóúñÁÉÍÓÚÑ\s]+?)(?:,|\s+mayor|\s+identificad|\s+con\s+c|\n)/i);
    if (matchArr && matchArr[1]) {
      let nombre = matchArr[1].trim();
      if (nombre.length > 3 && nombre.length < 80) {
        data.arrendador_nombre = limpiarTexto(nombre);
      }
    }
  }

  if (!data.arrendador_nombre) {
    const matchEmpresa = texto.match(/([A-Z][A-Z\s]{2,}(?:SAS|S\.A\.S\.?|SA|S\.A\.?|LTDA|LIMITADA))/i);
    if (matchEmpresa) { data.arrendador_nombre = limpiarTexto(matchEmpresa[1]); }
  }

  // ========== ARRENDATARIO ==========
  let matchArrt = texto.match(/Parte\s+Arrendataria\s+([A-ZÁÉÍÓÚÑ][A-Za-záéíóúñÁÉÍÓÚÑ\s]+?)(?:\n|CC|C\.C\.|$)/i);
  if (matchArrt && matchArrt[1]) {
    data.arrendatario_nombre = limpiarTexto(matchArrt[1]);
  }

  if (!data.arrendatario_nombre) {
    matchArrt = texto.match(/(?:EL\s+)?ARRENDATARIO[,:;\s]+([A-ZÁÉÍÓÚÑ][A-Za-záéíóúñÁÉÍÓÚÑ\s]+?)(?:,|\s+mayor|\s+identificad|\s+con\s+c|\n)/i);
    if (matchArrt && matchArrt[1]) {
      let nombre = matchArrt[1].trim();
      if (nombre.length > 3 && nombre.length < 80) {
        data.arrendatario_nombre = limpiarTexto(nombre);
      }
    }
  }

  // ========== DOCUMENTOS (CC) ==========
  const patronCC = /(?:CC|C\.C\.?)\s*(\d[\d.,]+)/gi;
  const todosCC = [...texto.matchAll(patronCC)];

  if (todosCC.length >= 2) {
    data.arrendador_doc = extraerNumero(todosCC[0][1]);
    data.arrendatario_doc = extraerNumero(todosCC[1][1]);
  } else if (todosCC.length === 1) {
    data.arrendador_doc = extraerNumero(todosCC[0][1]);
  }

  const matchNIT = texto.match(/NIT[.:\s]*([\d.,\-]+)/i);
  if (matchNIT) { data.arrendador_doc = extraerNumero(matchNIT[1]); }

  // ========== CANON ==========
  const patronesCanon = [
    /canon[^$\d]{0,50}?\$\s*([\d.,]+)/i,
    /\(\s*\$\s*([\d.,]+)\s*\)/i,
    /([\d]{1,3}(?:\.[\d]{3})+)\s*(?:pesos|m\/cte|mensuales)/i,
    /valor\s*(?:del)?\s*(?:canon|arriendo)[^$\d]{0,30}?\$?\s*([\d.,]+)/i
  ];
  for (const patron of patronesCanon) {
    const match = texto.match(patron);
    if (match) { const valor = parsearMoneda(match[1]); if (valor) { data.canon = valor; break; } }
  }

  // ========== DIRECCIÓN ==========
  const matchDir = texto.match(/((?:Calle|Carrera|Avenida|Diagonal|Transversal|Cra\.?|Cl\.?|Av\.?)\s*\d+[\w\s#\.\-]*)/i);
  if (matchDir) {
    let dir = matchDir[1].trim().substring(0, 100);
    data.direccion = limpiarTexto(dir);
  }

  // ========== CIUDAD ==========
  const matchCiudad = texto.match(/(Bogot[aá]\s*D\.?C\.?|Medell[ií]n|Cali|Barranquilla|Cartagena|Bucaramanga|Santa\s*Marta|Pereira|Manizales|C[uú]cuta|Ibagu[eé]|Villavicencio)/i);
  if (matchCiudad) { data.ciudad = limpiarTexto(matchCiudad[1]); }

  // ========== FECHA INICIO ==========
  const meses = {'enero':'01','febrero':'02','marzo':'03','abril':'04','mayo':'05','junio':'06','julio':'07','agosto':'08','septiembre':'09','octubre':'10','noviembre':'11','diciembre':'12'};
  const matchFecha = texto.match(/(\d{1,2})\s*(?:de)?\s*(enero|febrero|marzo|abril|mayo|junio|julio|agosto|septiembre|octubre|noviembre|diciembre)\s*(?:de|del)?\s*(\d{4})/i);
  if (matchFecha && meses[matchFecha[2].toLowerCase()]) { 
    const dia = matchFecha[1].padStart(2, '0');
    const mes = meses[matchFecha[2].toLowerCase()];
    const anio = matchFecha[3];
    if (parseInt(anio) >= 2015 && parseInt(anio) <= 2030) { data.fecha_inicio = `${anio}-${mes}-${dia}`; }
  }

  // ========== DURACIÓN ==========
  const matchDur = texto.match(/(?:duraci[oó]n|vigencia|plazo|t[eé]rmino)[^\d]{0,30}?(\d+)\s*\)?\s*(?:meses|a[nñ]os)/i);
  if (matchDur) { 
    const num = parseInt(matchDur[1]);
    data.duracion_meses = texto.toLowerCase().includes('año') && num <= 10 ? num * 12 : num;
  } else {
    const numEscrito = texto.match(/(?:UN|DOS|TRES|CUATRO|CINCO|SEIS|DOCE)\s*\(?\d*\)?\s*(?:MESES|AÑOS?)/i);
    if (numEscrito) {
      const map = {'UN':1,'DOS':2,'TRES':3,'CUATRO':4,'CINCO':5,'SEIS':6,'DOCE':12};
      for (const [palabra, num] of Object.entries(map)) {
        if (numEscrito[0].toUpperCase().includes(palabra)) {
          data.duracion_meses = numEscrito[0].toUpperCase().includes('AÑO') ? num * 12 : num;
          break;
        }
      }
    }
  }

  return data;
}

const datosExtraidos = extraerDatosContrato(textoContrato);
const contratoId = 'CTR-' + Date.now();

// Preservar datos binarios si existen
const output = {
  json: {
    id: contratoId,
    fecha: new Date().toISOString(),
    archivo: archivoNombre,
    ...datosExtraidos,
    estado: 'analizado',
    textoContrato: textoContrato
  }
};

// Pasar los datos binarios si existen
if (inputItem.binary) {
  output.binary = inputItem.binary;
}

return [output];

// InmoLawyer - Procesar Respuesta de Anthropic API
const inputData = $input.first().json;

// La respuesta de Anthropic viene en content[0].text
let respuestaTexto = '';
if (inputData.content && inputData.content[0] && inputData.content[0].text) {
  respuestaTexto = inputData.content[0].text;
} else if (inputData.text) {
  respuestaTexto = inputData.text;
} else if (inputData.response) {
  respuestaTexto = inputData.response;
}

// Obtener datos del contrato
let datosContrato;
try {
  datosContrato = $('Guardar Contrato').first().json;
} catch (e) {
  datosContrato = { id: 'CTR-UNKNOWN', textoContrato: '' };
}

let analisis = { alertas: [], score_riesgo: 0, resumen: '' };
let usedAI = false;

// Intentar parsear la respuesta JSON de la IA
if (respuestaTexto) {
  try {
    const jsonMatch = respuestaTexto.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      analisis = JSON.parse(jsonMatch[0]);
      usedAI = true;
    }
  } catch (e) {
    // Error parseando, usar fallback
  }
}

// Fallback: Análisis básico si no hay IA
if (!usedAI || !analisis.alertas || analisis.alertas.length === 0) {
  const texto = datosContrato.textoContrato || '';
  const textoLower = texto.toLowerCase();
  let scoreRiesgo = 0;
  analisis.alertas = [];

  if (textoLower.includes('depósito') || textoLower.includes('deposito')) {
    if (textoLower.includes('dinero') || textoLower.includes('efectivo') || textoLower.includes('suma')) {
      analisis.alertas.push({
        tipo: 'danger',
        titulo: 'Depósito en Dinero PROHIBIDO',
        descripcion: 'La Ley 820 Art. 16 prohíbe exigir depósitos en efectivo.',
        referencia_legal: 'Art. 16 Ley 820/2003',
        es_clausula_abusiva: true
      });
      scoreRiesgo += 30;
    }
  }

  const matchIncremento = texto.match(/(\d+)\s*%/);
  if (matchIncremento && parseInt(matchIncremento[1]) > 12) {
    analisis.alertas.push({
      tipo: 'danger',
      titulo: 'Incremento Excesivo (' + matchIncremento[1] + '%)',
      descripcion: 'El incremento supera el IPC permitido.',
      referencia_legal: 'Art. 20 Ley 820/2003',
      es_clausula_abusiva: true
    });
    scoreRiesgo += 25;
  }

  if (analisis.alertas.length === 0) {
    analisis.alertas.push({
      tipo: 'success',
      titulo: 'Sin Alertas Críticas',
      descripcion: 'No se detectaron problemas obvios.',
      referencia_legal: 'Ley 820/2003',
      es_clausula_abusiva: false
    });
  }

  analisis.score_riesgo = Math.min(scoreRiesgo, 100);
  analisis.resumen = 'Análisis básico completado.';
}

const alertasFormateadas = (analisis.alertas || []).map((a, i) => ({
  ...a,
  id: datosContrato.id + '-A' + i,
  contrato_id: datosContrato.id
}));

return [{
  json: {
    contratoId: datosContrato.id,
    datos: {
      arrendador: { nombre: datosContrato.arrendador_nombre, documento: datosContrato.arrendador_doc },
      arrendatario: { nombre: datosContrato.arrendatario_nombre, documento: datosContrato.arrendatario_doc },
