// InmoLawyer - Calcular Incrementos IPC segun DANE
const IPC_HISTORICO = {
  2025: 5.20, 2024: 5.20, 2023: 9.28, 2022: 13.12, 2021: 5.62, 2020: 1.61,
  2019: 3.80, 2018: 3.18, 2017: 4.09, 2016: 5.75, 2015: 6.77,
  2014: 3.66, 2013: 1.94, 2012: 2.44, 2011: 3.73, 2010: 3.17
};

const inputData = $input.first().json;
const datosContrato = inputData.datos || {};
const contratoId = inputData.contratoId;

const fechaInicioStr = datosContrato.fecha_inicio;
const canonInicial = datosContrato.canon;

const incrementos = [];
let fechasImportantes = {};

if (fechaInicioStr && canonInicial) {
  const fechaInicio = new Date(fechaInicioStr);
  const anioInicio = fechaInicio.getFullYear();
  const mesInicio = fechaInicio.getMonth();
  const diaInicio = fechaInicio.getDate();
  const anioActual = new Date().getFullYear();

  let canonActual = canonInicial;

  for (let anio = anioInicio + 1; anio <= anioActual; anio++) {
    const ipc = IPC_HISTORICO[anio] || IPC_HISTORICO[anio - 1] || 5.0;
    const incremento = Math.round(canonActual * (ipc / 100));
    const canonNuevo = canonActual + incremento;

    incrementos.push({
      id: contratoId + '-INC-' + anio,
      contrato_id: contratoId,
      anio: anio,
      ipc_aplicado: ipc,
      canon_anterior: canonActual,
      incremento: incremento,
      canon_nuevo: canonNuevo
    });

    canonActual = canonNuevo;
  }

  const duracionMeses = datosContrato.duracion_meses || 12;

  const fechaVencimiento = new Date(fechaInicio);
  fechaVencimiento.setMonth(fechaVencimiento.getMonth() + duracionMeses);

  const hoy = new Date();
  let proximoAniversario = new Date(hoy.getFullYear(), mesInicio, diaInicio);
  if (proximoAniversario <= hoy) {
    proximoAniversario.setFullYear(proximoAniversario.getFullYear() + 1);
  }

  const fechaNotifIncremento = new Date(proximoAniversario);
  fechaNotifIncremento.setMonth(fechaNotifIncremento.getMonth() - 1);

  const fechaNotifDesocupacion = new Date(fechaVencimiento);
  fechaNotifDesocupacion.setMonth(fechaNotifDesocupacion.getMonth() - 3);

  const ipcProximo = IPC_HISTORICO[anioActual] || 5.20;
  const incrementoProximo = Math.round(canonActual * (ipcProximo / 100));

  fechasImportantes = {
    vencimiento: fechaVencimiento.toISOString().split('T')[0],
    notificacion_incremento: fechaNotifIncremento.toISOString().split('T')[0],
    notificacion_desocupacion: fechaNotifDesocupacion.toISOString().split('T')[0],
    proximo_incremento: {
      fecha: proximoAniversario.toISOString().split('T')[0],
      ipc: ipcProximo,
      canon_actual: canonActual,
      incremento_proyectado: incrementoProximo,
      canon_proyectado: canonActual + incrementoProximo
    }
  };
}

return [{
  json: {
    ...inputData,
    incrementos: incrementos,
    fechas_importantes: fechasImportantes,
    canon_actual_calculado: incrementos.length > 0 ? incrementos[incrementos.length - 1].canon_nuevo : canonInicial
  }
}];

// Preparar contexto para el chat con datos del contrato
// Las alertas se buscarán en la hoja de Sheets si es necesario

const contrato = $input.first().json;
const pregunta = $('Webhook - Consulta Chat').first().json.body.pregunta;

// Preparar el contexto con la información del contrato
const contexto = {
  contratoId: contrato.id,
  pregunta: pregunta,
