    arrendador: contrato.arrendador_nombre || 'No especificado',
    arrendatario: contrato.arrendatario_nombre || 'No especificado',
    canon: contrato.canon,
    direccion: contrato.direccion,
    ciudad: contrato.ciudad,
    fechaInicio: contrato.fecha_inicio,
    duracionMeses: contrato.duracion_meses,
    estado: contrato.estado
  },
  textoContrato: contrato.textoContrato || '',
  // Información sobre cláusulas potencialmente problemáticas detectadas en el texto
  clausulasDetectadas: []
};

// Analizar el texto del contrato para detectar cláusulas problemáticas
const texto = (contrato.textoContrato || '').toLowerCase();

if (texto.includes('depósito') || texto.includes('deposito')) {
  contexto.clausulasDetectadas.push('Cláusula de depósito detectada - Verificar si cumple Art. 16 Ley 820');
}
if (texto.includes('10%') || texto.includes('incremento') && texto.includes('fijo')) {
  contexto.clausulasDetectadas.push('Incremento fijo detectado - Posible violación Art. 20 Ley 820 (máximo IPC)');
}
if (texto.includes('sin preaviso') || texto.includes('cualquier momento')) {
  contexto.clausulasDetectadas.push('Terminación sin preaviso - Posible violación Arts. 22-24 Ley 820');
}

return [{ json: contexto }];

// Formatear la respuesta del chat para guardar y responder

