  created_at: new Date().toISOString()
};

// Preparar respuesta para el webhook
const respuestaWebhook = {
  success: true,
  consultaId: consultaId,
  respuesta: respuestaLLM,
  contratoId: webhookData.contratoId
};

return [{ json: { ...datosGuardar, _respuestaWebhook: respuestaWebhook } }];

